mapper.select:
SELECT t.attr as attr, t.data as data, t.dsc as dsc, t.nums as nums, t.price as price, t.tat as tat, t.total as total, t.tpt as tpt, t.unit as unit, t.warehouse as warehouse, t.name as name, t.supplier as supplier, t.time as time, t.number as number, t.type as type FROM ( -- 1. 采购出库（type = 1） SELECT bi.attr, bi.data, bi.dsc, bi.nums, bi.price, bi.tat, bi.total, bi.tpt, bi.unit, bi.warehouse, g.name AS name, bor.supplier, bor.time, bor.number, 1 AS type FROM bor_info bi LEFT JOIN goods g ON bi.goods = g.id LEFT JOIN bor ON bi.pid = bor.id
AND bor.time >= #{query.startTime}
AND bor.time <= #{query.endTime}
AND bor.supplier = #{query.supplier}
AND bor.number LIKE CONCAT('%', #{query.number}, '%')
AND bi.warehouse = #{query.warehouse}
AND g.name LIKE CONCAT('%', #{query.name}, '%')
AND bi.data LIKE CONCAT('%', #{query.data}, '%')
UNION ALL -- 2. 采购退货（type = 0） SELECT brei.attr, brei.data, brei.dsc, brei.nums, brei.price, brei.tat, brei.total, brei.tpt, brei.unit, brei.warehouse, g.name AS name, bre.supplier, bre.time, bre.number, 0 AS type FROM bre_info brei LEFT JOIN goods g ON brei.goods = g.id LEFT JOIN bre ON brei.pid = bre.id
AND bre.time >= #{query.startTime}
AND bre.time <= #{query.endTime}
AND bre.supplier = #{query.supplier}
AND bre.number LIKE CONCAT('%', #{query.number}, '%')
AND brei.warehouse = #{query.warehouse}
AND g.name LIKE CONCAT('%', #{query.name}, '%')
AND brei.data LIKE CONCAT('%', #{query.data}, '%')
) t
AND t.type = #{query.type}
ORDER BY t.time DESC

